const api = $input.item.json;
const dbId = String($('Loop: oferta por oferta').item.json.id || '');
const id = api.id ? String(api.id) : dbId;

// LOG: ver la respuesta real de la API (quitar cuando esté mapeado bien)
console.log('[flexicar-enrich] id=' + id + ' keys=' + Object.keys(api).join(','));
console.log('[flexicar-enrich] raw=' + JSON.stringify(api).slice(0, 1500));

if (!id) {
  await new Promise(r => setTimeout(r, 800));
  return [{ json: { id: null, hasUpdates: false, updateSql: null } }];
}

function esc(v) {
  if (v === null || v === undefined) return "NULL";
  if (typeof v === "number") return isNaN(v) ? "NULL" : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}

function normalizeBody(raw) {
  const s = String(raw || "").toLowerCase();
  if (s.indexOf("suv") !== -1 || s.indexOf("4x4") !== -1 || s.indexOf("todoterreno") !== -1) return "SUV";
  if (s.indexOf("berlina") !== -1 || s.indexOf("sedan") !== -1) return "Berlina";
  if (s.indexOf("familiar") !== -1 || s.indexOf("estate") !== -1) return "Familiar";
  if (s.indexOf("coupe") !== -1 || s.indexOf("coupé") !== -1) return "Coupé";
  if (s.indexOf("cabrio") !== -1 || s.indexOf("convert") !== -1) return "Cabrio";
  if (s.indexOf("monovolumen") !== -1 || s.indexOf("mpv") !== -1) return "Monovolumen";
  if (s.indexOf("hatchback") !== -1) return "Berlina";
  return raw || "";
}

// Intentar múltiples nombres de campo posibles para cada dato
const colorVal = api.color || api.colorName || api.colour || api.colorExterior || '';
const doorsVal = api.doors || api.numDoors || api.numberOfDoors || api.puertas || 0;
const seatsVal = api.seats || api.numSeats || api.numberOfSeats || api.plazas || 0;
const hpVal    = api.hp || api.power || api.cv || api.potencia || api.horsePower || 0;

// Cilindrada: puede venir en cc (1500) o en litros (1.5)
const cylRaw = api.cylinder || api.displacement || api.cc || api.engineDisplacement || api.cilindrada || 0;
const cylCC  = cylRaw > 100 ? Math.round(cylRaw) : Math.round(cylRaw * 1000); // normalizar a cc

const consumVal = api.mixedConsumption || api.consumption || api.fuelConsumption || api.consumo || 0;
const bodyVal   = api.body || api.bodyType || api.carType || api.carroceria || api.bodyWork || '';

// Imágenes: puede ser array de strings o array de {image: url}
let imgUrls = [];
const imgsRaw = api.images || api.photos || api.gallery || [];
if (Array.isArray(imgsRaw) && imgsRaw.length > 0) {
  if (typeof imgsRaw[0] === 'string') {
    imgUrls = imgsRaw.filter(Boolean).slice(0, 20);
  } else {
    imgUrls = imgsRaw.map(function(i) { return i.image || i.url || i.src || ''; }).filter(Boolean).slice(0, 20);
  }
}

// Tracción y CO2: puede venir en dataSheet (array strings) o en campos directos
const dataSheetArr = api.dataSheet || api.specs || api.characteristics || api.features || [];
const tractionDirect = api.traction || api.traccion || api.driveType || api.tractionType || '';
const co2Direct = api.co2 || api.emissions || api.co2Emissions || '';

const sets = [];

if (colorVal)              sets.push("color = COALESCE(NULLIF(color,''), " + esc(colorVal) + ")");
if (doorsVal > 0)          sets.push("doors = COALESCE(NULLIF(doors,0), " + doorsVal + ")");
if (seatsVal > 0)          sets.push("seats = COALESCE(NULLIF(seats,0), " + seatsVal + ")");
if (hpVal > 0)             sets.push("power_cv = COALESCE(NULLIF(power_cv,0), " + hpVal + ")");
if (cylCC > 0)             sets.push("displacement = COALESCE(NULLIF(displacement,''), '" + cylCC + "')");
if (consumVal > 0)         sets.push("consumption = COALESCE(NULLIF(consumption,0), " + consumVal + ")");
if (bodyVal)               sets.push("body_type = COALESCE(NULLIF(body_type,''), " + esc(normalizeBody(bodyVal)) + ")");
if (imgUrls.length > 0) {
  sets.push("image_url = COALESCE(NULLIF(image_url,''), " + esc(imgUrls[0]) + ")");
  sets.push("images = COALESCE(NULLIF(images,''), " + esc(JSON.stringify(imgUrls)) + ")");
}

// Tracción: primero campo directo, luego buscar en dataSheet
if (tractionDirect) {
  const td = tractionDirect.toLowerCase();
  const trVal = td.indexOf('total') !== -1 || td.indexOf('integral') !== -1 || td.indexOf('4x4') !== -1 ? '4x4'
    : td.indexOf('tras') !== -1 ? 'Trasera'
    : td.indexOf('del') !== -1 ? 'Delantera' : tractionDirect;
  sets.push("traction = COALESCE(NULLIF(traction,''), " + esc(trVal) + ")");
} else if (Array.isArray(dataSheetArr) && dataSheetArr.length > 0) {
  const ds = dataSheetArr.join(' ').toLowerCase();
  if (ds.indexOf('tracción total') !== -1 || ds.indexOf('tracción integral') !== -1 || ds.indexOf('4x4') !== -1) {
    sets.push("traction = COALESCE(NULLIF(traction,''), '4x4')");
  } else if (ds.indexOf('tracción trasera') !== -1) {
    sets.push("traction = COALESCE(NULLIF(traction,''), 'Trasera')");
  } else if (ds.indexOf('tracción delantera') !== -1) {
    sets.push("traction = COALESCE(NULLIF(traction,''), 'Delantera')");
  }
}

// CO2: primero campo directo, luego buscar en dataSheet
if (co2Direct) {
  sets.push("co2 = COALESCE(NULLIF(co2,''), " + esc(String(co2Direct)) + ")");
} else if (Array.isArray(dataSheetArr) && dataSheetArr.length > 0) {
  const dsText = dataSheetArr.join(' ');
  const wltpIdx = dsText.toLowerCase().indexOf('emisiones wltp ice');
  if (wltpIdx !== -1) {
    const after = dsText.slice(wltpIdx + 18, wltpIdx + 60);
    const m = after.match(/(\d+)/);
    if (m) sets.push("co2 = COALESCE(NULLIF(co2,''), '" + m[1] + "')");
  }
}

sets.push("enrich_tried_at = NOW()");

const updateSql = "UPDATE moveadvisor_market_offers SET " + sets.join(", ") + ", updated_at = NOW() WHERE id = '" + id.replace(/'/g, "''") + "'";

console.log('[flexicar-enrich] sets count=' + sets.length + ' sql=' + updateSql.slice(0, 300));

await new Promise(r => setTimeout(r, 800));

return [{ json: { id: id, hasUpdates: true, updateSql: updateSql } }];
